15→interface ItemCardProps {
16→  item: ItemCardItem
17→  compact?: boolean
18→}
19→
20→const TYPE_COLORS: Record<string, string> = {
21→  BOOKMARK: 'blue',
22→  TEXT_NOTE: 'green',
23→  VOICE_NOTE: 'orange',
24→  DRIVE_DOC: 'violet',
25→  HIGHLIGHT: 'yellow',
