import { test, expect, type Page } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'
const uniqueId = `demo-${Date.now()}`

async function login(page: Page) {
  await page.goto('/login')
  await page.getByLabel('Email').fill('ketan@example.com')
  await page.getByLabel('Password').fill('testpassword123')
  await page.getByRole('button', { name: 'Login' }).click()
  await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()
}

test.describe('Capture Round-Trip', () => {
  test('Capture a text note and retrieve it', async ({ page }) => {
    const noteTitle = `Demo Note ${uniqueId}`
    const noteContent = `This is a demo text note created during the capture round-trip test. ID: ${uniqueId}`

    await login(page)

    // Navigate to capture and select Note tab
    await page.goto('/capture')
    await page.getByRole('tab', { name: /Note/i }).click()

    // Fill in the note form
    await page.getByLabel('Title').fill(noteTitle)
    await page.getByLabel('Content').fill(noteContent)

    if (isManual) await page.pause()

    // Submit
    await page.getByRole('button', { name: 'Save Note' }).click()

    // Success redirects to /
    await expect(page).toHaveURL('/')

    // Navigate to browse and find the note
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')
    await expect(page.getByText(noteTitle)).toBeVisible()

    if (isManual) await page.pause()

    // Click into the note and verify detail page
    await page.getByText(noteTitle).click()
    await expect(page).toHaveURL(/\/items\//)
    await expect(page.getByText(noteTitle)).toBeVisible()
    await expect(page.getByText(noteContent)).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Capture a bookmark and retrieve it', async ({ page }) => {
    const bookmarkTitle = `Demo Bookmark ${uniqueId}`
    const bookmarkUrl = `https://example.com/${uniqueId}`

    await login(page)

    // Navigate to capture — Bookmark tab is default
    await page.goto('/capture')

    // Fill in the bookmark form
    await page.getByLabel('URL').fill(bookmarkUrl)
    await page.getByLabel('Title').fill(bookmarkTitle)

    if (isManual) await page.pause()

    // Submit
    await page.getByRole('button', { name: 'Save Bookmark' }).click()

    // Success redirects to /
    await expect(page).toHaveURL('/')

    // Navigate to browse and find the bookmark
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')
    await expect(page.getByText(bookmarkTitle)).toBeVisible()

    if (isManual) await page.pause()

    // Click into the bookmark and verify detail page
    await page.getByText(bookmarkTitle).click()
    await expect(page).toHaveURL(/\/items\//)
    await expect(page.getByText(bookmarkTitle)).toBeVisible()
    await expect(page.getByText(bookmarkUrl)).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Search retrieves captured items', async ({ page }) => {
    const searchNoteTitle = `Search Note ${uniqueId}`
    const searchNoteContent = `Searchable content for round-trip verification. ID: ${uniqueId}`

    await login(page)

    // Capture a note first
    await page.goto('/capture')
    await page.getByRole('tab', { name: /Note/i }).click()
    await page.getByLabel('Title').fill(searchNoteTitle)
    await page.getByLabel('Content').fill(searchNoteContent)
    await page.getByRole('button', { name: 'Save Note' }).click()
    await expect(page).toHaveURL('/')

    // Search for the note
    await page.goto('/search')
    await page.getByPlaceholder('Search your knowledge base...').fill(searchNoteTitle)
    // Press Enter or wait for results — search may auto-trigger or need submit
    await page.getByPlaceholder('Search your knowledge base...').press('Enter')
    await page.waitForLoadState('networkidle')

    await expect(page.getByText(searchNoteTitle)).toBeVisible()

    if (isManual) await page.pause()
  })
})

